CREATE TABLE `${schema}` (
  id bigint(20) AUTO_INCREMENT,
  uid BIGINT UNIQUE,
  owner_uid bigint(20),
  creator_uid bigint(20),
  agenda_uid bigint(20),
  location_uid bigint(20),
  slug VARCHAR(255) NOT NULL UNIQUE,
  title VARCHAR(2000) NOT NULL,
  description VARCHAR(2000) NOT NULL,
  long_description TEXT,
  keywords VARCHAR(2000),
  conditions VARCHAR(2000),
  image VARCHAR(1500),
  draft TINYINT(1) DEFAULT 1,
  private TINYINT(1) DEFAULT 0,
  timezone VARCHAR(255) NOT NULL,
  timings TEXT,
  accessibility VARCHAR( 100 ),
  age VARCHAR( 50 ),
  registration VARCHAR(2000),
  `references` VARCHAR(2000),
  links VARCHAR(2000),
  created_at DATETIME NOT NULL,
  updated_at DATETIME NOT NULL,
  deleted_at DATETIME,
  file_key varchar(32),
  UNIQUE INDEX id_idx (id),
  UNIQUE INDEX uid_idx (uid),
  UNIQUE INDEX slug_idx (slug),
  INDEX agenda_uid_idx (agenda_uid),
  INDEX owner_uid_idx (owner_uid),
  INDEX location_uid_idx (location_uid)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;


INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at` ) VALUES
(147291, 71477747, 65570947, 21475128, 88670536, 
  'decouverte-du-handball-et-valorisation-du-mondial-de-handball',
  '{"fr":"Découverte du handball et valorisation du mondial de Handball"}',
  '{"fr":"Animation de proximité sur les city-stade des quartiers prioritaires ou veille de la politique de la ville  du 24 au 28 octobre"}',
  '{"fr":"Date du projet : Du lundi 24 au vendredi 28 octobre\\n\\nHoraires du projet : De 14h00 à 16h30\\n\\nDéroulement du projet : Les quatre premiers jours vont permettre de faire découvrir le handball en initiant les enfants, les adolescents, les adultes aux spécificités de ce sport. Sur le dernier jour, un tournoi ludique pour les 10-17 ans sera organisé.\\n\\nObjectifs du projet :\\n\\nFavoriser la découverte du handball et valoriser l’évènement « championnat du monde de handball » Promouvoir le sport comme outil de santé Promouvoir le sport comme outil d’égalité notamment entre le public féminin et masculin\\n\\nLieu :\\n\\nLe lundi 24 octobre : city-stade du quartier Saint-Sauveur Le mardi 25 octobre : city-stade du quartier Saint-Michel Le mercredi 26 octobre : city-stade du quartier du Pont-Féron Le jeudi 27 octobre : gymnase Godard du complexe sportif Saint-Sauveur Le vendredi 28 octobre : gymnase Godard du complexe sportif Saint-Sauveur\\n\\nIntervenants :\\n\\nUn animateur de la Maison d’Activités Saint-Sauveur Un éducateur du club de handball de Flers"}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-24T12:00:00.000Z","end":"2016-10-24T13:00:00.000Z"},{"begin":"2016-10-24T13:00:00.000Z","end":"2016-10-24T14:30:00.000Z"},{"begin":"2016-10-25T12:00:00.000Z","end":"2016-10-25T13:00:00.000Z"},{"begin":"2016-10-25T13:00:00.000Z","end":"2016-10-25T14:30:00.000Z"},{"begin":"2016-10-26T12:00:00.000Z","end":"2016-10-26T13:00:00.000Z"},{"begin":"2016-10-26T13:00:00.000Z","end":"2016-10-26T14:30:00.000Z"},{"begin":"2016-10-27T12:00:00.000Z","end":"2016-10-27T13:00:00.000Z"},{"begin":"2016-10-27T13:00:00.000Z","end":"2016-10-27T14:30:00.000Z"},{"begin":"2016-10-28T12:00:00.000Z","end":"2016-10-28T13:00:00.000Z"},{"begin":"2016-10-28T13:00:00.000Z","end":"2016-10-28T14:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":false,"sl":true}', '{"min":8,"max":17}', '[]', '2016-11-04 09:18:42', '2016-11-04 09:18:42', NULL ),
(145633, 78596875, 96538699, NULL, 44155844, 'decouverte-du-handball-pour-des-eleves-de-quartier-prioritaire', '{"fr":"Découverte du handball pour des élèves de quartier prioritaire"}', '{"fr":"Permettre aux 53 élèves de la section handball d''un collège REP d''assister à un match du Mondial de handball"}', '{"fr":"Notre objectif principal est de favoriser un accès au sport pour tous.\\n\\nUn tel projet permettrait de promouvoir le handball chez les jeunes issus d''un quartier prioritaire, et scolarisés dans un collège classé REP. En effet, nous voyons au quotidien le sport comme un formidable instrument d’éducation populaire et d’intégration. Assister à un match de l''équipe de France peut sans aucun doute motiver et inspirer les élèves, et favoriser pour eux l''accès à une pratique sportive régulière. Participer à une manifestation sportive de cette envergure nous semble être un bon moyen pour ces jeunes de s’inscrire dans un parcours de réussite via l’identification à des sportifs de hauts niveaux."}', '{"fr":",   collège REP,   section handball,  quartier prioritaire"}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-01-17T14:30:00.000Z","end":"2017-01-17T15:30:00.000Z"},{"begin":"2017-01-17T15:30:00.000Z","end":"2017-01-17T16:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":12,"max":15}', '[]', '2016-11-04 09:20:07', '2016-11-04 09:20:07', NULL ),
(146651, 53583605, 38565623, 27545135, 72989933, 'decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes', '{"fr":"Découverte du milieu marin de Martinique. Visite de 1h par groupe de 12 personnes"}', '{"fr":"Ecotourisme Nautique en Martinique"}', '{"fr":"Dénébola développe l’Ecotourisme Nautique en Martinique et propose de venir participer à ses ateliers pédagogiques sur les écosystèmes marins. Un premier échange sera fait sur l’écotourisme nautique (comment réduire notre impact sur le milieu marin lors de la pratique de loisirs nautiques : les éco-gestes, la réglementation, l’éconavigation...). Ensuite l’intervenant donnera quelques notions sur la navigation à la voile, à bord du voilier qui sera à quai, afin de partager avec le public cette passion pour une navigation plus douce et plus silencieuse. Puis, il présentera le CHATROU (outil pédagogique à bord du voilier) et le visiteur choisira parmi les 8 thèmes développés celui qui lui plait (poissons, coraux, tortues et cétacés, mollusques et crustacés, oiseaux marins, mangrove, 7ème continent et iguanes endémiques). Le CHATROU a été réalisé avec des partenaires spécialistes de chaque thème et a été conçu spécialement pour un public de loisir. C’est donc l’idéal pour enrichir ses connaissances tout en s’amusant !\\n\\nVisite de 1h par groupe de 12 personnes."}', '{"fr":",    Ecotourisme,    Nautisme,   Martinique, atelié pédagogique"}', NULL, '{"filename":"event_decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes_633546.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes_633546.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouverte-du-milieu-marin-de-martinique-visite-de-1h-par-groupe-de-12-personnes_633546.jpg","size":{"height":null,"width":null}}]}', 1, 0, 'Europe/Paris', '[{"begin":"2016-10-15T08:00:00.000Z","end":"2016-10-15T09:00:00.000Z"},{"begin":"2016-10-15T09:00:00.000Z","end":"2016-10-15T10:00:00.000Z"},{"begin":"2016-10-15T12:00:00.000Z","end":"2016-10-15T13:00:00.000Z"},{"begin":"2016-10-15T13:00:00.000Z","end":"2016-10-15T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":10,"max":99}', '["0696 170 700"]', '2016-11-04 09:19:18', '2016-11-04 09:19:18', NULL );

