(146687, 2875149, 38565623, 27545135, 64235133, 
  'decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma', 
  '{"fr":"Découverte du pavillon pédagogique «Energies renouvelables» du RSMA"}', 
  '{"fr":"Visite du pavillon pédagogique du RSMA"}', 
  '{"fr":"Déroulement de la visite :\\n\\n- Départ en bus vers le site (le lieu de RDV sera communiqué à l’inscription).\\n\\n- Accueil du RSMA\\n\\n- Visite du pavillon pédagogique. Objectif : expliquer au visiteur le fonctionnement d’un chauffe-eau solaire,\\n\\n- Intervention des apprentis sur leur métier, leurs visions de la filière chauffe-eau solaire (solariste)\\n\\n- Présentation de la filière solaire en Martinique, les acteurs, la réglementation, les métiers, les dispositifs d’aides."}', 
  '{"fr":["RSMA", "Energie solaire", "Energies renouvelables", "Martinique"]}', 
  NULL, 
  '{"filename":"event_decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma_877473.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma_877473.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouverte-du-pavillon-pedagogique-energies-renouvelables-du-rsma_877473.jpg","size":{"height":null,"width":null}}]}', 
  1, 
  0, 
  'Europe/Paris', 
  '[{"begin":"2016-10-12T11:00:00.000Z","end":"2016-10-12T14:30:00.000Z"}]', 
  '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', 
  '{"min":18,"max":99}', 
  '["vie@pnr-martinique.com","0696 220 310"]', 
  '2016-11-04 09:19:16', 
  '2016-11-04 09:19:16', 
  NULL,
  '[78596875,39592710,85595460]'
),

(146447, 59481036, 54534699, 27545135, 88599907, 'decouvrez-hololens-avec-infinite-square', '{"fr":"Découvrez HoloLens avec Infinite Square !"}', '{"fr":"#HoloLens #Réalitéaugmentée #Microsoft #Player"}', '{"fr":"Nous vous invitons à découvrir HoloLens, la technologie de réalité augmentée de Microsoft, au travers du programme suivant :\\n\\n- Présentation des différentes réalités\\n\\n- Qu’est-ce que HoloLens et comment ça marche ?\\n\\n- Les usages concrets de HoloLens\\n\\n- Comment développer sur HoloLens ?\\n\\n- Q&A Soyez attentifs, un petit quizz vous sera proposé en fin de session.\\n\\nLes 5 gagnants auront la possibilité de tester HoloLens !\\n\\nNous avons le plaisir d''accueillir : Jonathan ANTOINE. Jonathan ANTOINE est développeur .NET chez Infinite Square. Il est reconnu Microsoft MVP (Most Valuable Professional) dans la catégorie Développement d’applications Windows."}', '{}', NULL, '{"filename":"event_decouvrez-hololens-avec-infinite-square_768930.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-hololens-avec-infinite-square_768930.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-hololens-avec-infinite-square_768930.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-18T13:00:00.000Z","end":"2016-10-18T14:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '["https://intra.epitech.eu/module/2016/G-EPI-007/PAR-0-1/#!/all/Conference-4-Decouvrez-HoloLens-avec-Infinite-Square"]', '2016-11-04 09:19:29', '2016-11-04 09:19:29', NULL, '[39592710,85595460]' );

