(146739, 1025581, 45388483, NULL, 20067179, 'decouvertes-des-metiers-du-chu', '{"fr":"Découvertes des Métiers du CHU"}', '{"fr":"Présentation des différentes métiers dans un CHU"}', '{"fr":"Conférences sur la relation entre alimentation et cancer, alimentation et la vision, l’alimentation chez les personnes agées, présentation des différents métiers du CHU."}', '{}', NULL, '{"filename":null,"credits":null,"size":{"height":null,"width":null},"variants":[]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-10T07:00:00.000Z","end":"2016-10-10T10:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":16,"max":99}', '[]', '2016-11-04 09:19:13', '2016-11-04 09:19:13', NULL ),

(146462, 88161554, 23307857, NULL, 73924923, 'decouvrez-le-livre-le-plus-froid-du-monde', '{"fr":"Découvrez le livre le plus froid du monde"}', '{"fr":"Le livre qui vous dévoile en direct ses secrets et ses expériences à -196°C"}', '{"fr":"Avec la collaboration d’une étudiante en illustration scientifique, l’équipe **La Physique Autrement ** a créé le livre le plus froid du monde. Venez découvrir le résultat, à mi-chemin entre cuve à expériences, livre scientifique et recueil d''images !"}', '{"fr":["physique quantique","livre","conférence","froid"]}', NULL, '{"filename":"event_decouvrez-le-livre-le-plus-froid-du-monde_258353.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-le-livre-le-plus-froid-du-monde_258353.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-le-livre-le-plus-froid-du-monde_258353.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-13T10:30:00.000Z","end":"2016-10-13T11:30:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":15,"max":99}', '[]', '2016-11-04 09:19:28', '2016-11-04 09:19:28', NULL ),
(146160, 88181677, 14963029, NULL, 22263034, 'decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy', '{"fr":"Découvrez le nouveau film avec Pierre Niney en avant-première au Ciné d''Issy !"}', '{"fr":"Venez découvrir l''histoire de Jacques-Yves Cousteau au Ciné d''Issy/"}', '{"fr":"1948 : Jacques Cousteau, sa femme et ses deux fils, vivent au paradis dans une jolie maison surplombant la mer Méditerranée. Mais Cousteau ne rêve que d''aventure. Grâce à son invention, un scaphandre autonome qui permet de respirer sous l''eau, il a découvert un nouveau monde. Désormais, ce monde il va l''explorer. Et pour ça, il est prêt à tout sacrifier.\\n\\n[https://www.youtube.com/watch?v=Goy8YMc3KHg](https://www.youtube.com/watch?v=Goy8YMc3KHg)"}', '{}', NULL, '{"filename":"event_decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy_164509.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy_164509.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-le-nouveau-film-avec-pierre-niney-en-avant-premiere-au-cine-d-issy_164509.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2016-10-09T14:30:00.000Z","end":"2016-10-09T16:00:00.000Z"}]', '{"mi":true,"hi":true,"pi":true,"vi":true,"sl":true}', '{"min":7,"max":99}', '[]', '2016-11-04 09:19:43', '2016-11-04 09:19:43', NULL ),

(147604, 686270, 97862464, NULL, 87998085, 'decouvrez-les-coulisses-du-futur-musee-albert-kahn', '{"fr":"Découvrez les coulisses du futur Musée Albert-Kahn"}', '{"fr":"Visite inédite du site, jusqu''à la fin des travaux de rénovation"}', '{"fr":"MUSEE DEPARTEMENTAL ALBERT-KAHN\\n\\nPrélude d''un nouveau musée\\n\\nJusqu''à la fin des travaux de rénovation, le musée départemental Albert-Kahn propose au public de passer de l''autre côté des palissades et bénéficier d''une visite inédite du site, à travers une promenade en images dans le jardin. Pendant les travaux, le Département a choisi de ne pas fermer le site et de continuer d''accueillir le public, avec une offre inédite : découvrir l''envers du décor.\\n\\n A travers cette nouvelle expérience, le visiteur aura une occasion exceptionnelle de découvrir les coulisses du projet du musée et la préparation de la future offre culturelle proposée à partir de mars 2018\\\\. Le parcours proposé, uniquement sur réservation préalable, s''appuie sur une série d''images présentées en bouquets répartis sur le site : autochromes du jardin, photographies sur l''histoire du site et vues des bâtiments du nouveau musée, pour découvrir ou de redécouvrir Albert Kahn, son œuvre, la richesse des collections et le programme de rénovation. Ils permettent de visiter l''ensemble des scènes paysagères qui composent le jardin. Prenez-vite rendez-vous !\\n\\nInformations pratiques :\\n\\nMusée départemental Albert-Kahn\\n\\n10-14, rue du Port - 92100 Boulogne-Billancourt\\n\\nTél. : 01 55 19 28 00 - museealbertkahn@hauts-de-seine.fr - albert-kahn.hauts-de-seine.fr\\n\\nAccès au site: 1, rue des Abondances - 92100 Boulogne-Billancourt\\n\\nBilletterie : 1bis, rue des Abondances\\n\\nIndividuels\\n\\nDurée estimée de la visite : 1h30\\\\. Sur réservation uniquement.\\n\\nPromenade accompagnée d''un médiateur\\n\\nJusqu''au 30 avril\\n\\n-          Le samedi à 15h\\n\\n-          Le dimanche à 11h\\n\\n-          Le dimanche à 15h\\n\\nDu 1er mai au 30 septembre\\n\\n-          Le mardi à 15h\\n\\n-          Le vendredi à 15h\\n\\n-          Le samedi à 14h\\n\\n-          Le samedi à 16h30\\n\\n-          Le dimanche à 11h\\n\\n-          Le dimanche à 15h \\n\\nTarifs : 3 €, tarif réduit 1,50 €.\\n\\nGroupes\\n\\nOrganisation de visites sur mesure sur demande (minimum 10 personnes)\\n\\nTarifs  (minimum de 10 personnes) : 1,50 € par visiteur.\\n\\nInformations/réservations : accueilmak@hauts-de-seine.fr ou\\n\\naccueilmak@hauts-de-seine.fr ou 01 55 19 28 27"}', '{}', NULL, '{"filename":"event_decouvrez-les-coulisses-du-futur-musee-albert-kahn_351167.jpg","credits":null,"size":{"height":null,"width":null},"variants":[{"type":"full","filename":"evfevent_decouvrez-les-coulisses-du-futur-musee-albert-kahn_351167.jpg","size":{"height":null,"width":null}},{"type":"thumbnail","filename":"evtbevent_decouvrez-les-coulisses-du-futur-musee-albert-kahn_351167.jpg","size":{"height":null,"width":null}}]}', 0, 0, 'Europe/Paris', '[{"begin":"2017-01-21T14:00:00.000Z","end":"2017-01-21T16:00:00.000Z"},{"begin":"2016-10-15T13:00:00.000Z","end":"2016-10-15T15:00:00.000Z"},{"begin":"2017-01-15T14:00:00.000Z","end":"2017-01-15T16:00:00.000Z"},{"begin":"2017-04-29T13:00:00.000Z","end":"2017-04-29T15:00:00.000Z"},{"begin":"2017-01-15T10:00:00.000Z","end":"2017-01-15T12:00:00.000Z"},{"begin":"2017-04-23T09:00:00.000Z","end":"2017-04-23T11:00:00.000Z"},{"begin":"2017-01-14T14:00:00.000Z","end":"2017-01-14T16:00:00.000Z"},{"begin":"2017-04-16T13:00:00.000Z","end":"2017-04-16T15:00:00.000Z"},{"begin":"2017-01-08T14:00:00.000Z","end":"2017-01-08T16:00:00.000Z"},{"begin":"2017-04-15T13:00:00.000Z","end":"2017-04-15T15:00:00.000Z"},{"begin":"2017-01-08T10:00:00.000Z","end":"2017-01-08T12:00:00.000Z"},{"begin":"2017-04-09T09:00:00.000Z","end":"2017-04-09T11:00:00.000Z"},{"begin":"2017-01-07T14:00:00.000Z","end":"2017-01-07T16:00:00.000Z"},{"begin":"2017-04-02T13:00:00.000Z","end":"2017-04-02T15:00:00.000Z"},{"begin":"2017-01-01T14:00: